"use client";

import React from "react";

import Button, { ButtonProps } from "@mui/material/Button";

import type {
  ForwardStyledProps,
  OverridableComponent,
} from "../../types/shared/component";
import { ScreenReaderInput } from "./collapsible-trigger";

export type CollapsibleButtonProps = ForwardStyledProps<{
  defaultChecked?: boolean;
  component?: React.ElementType;
}>;

export const CollapsibleButton = React.forwardRef<
  HTMLLabelElement,
  CollapsibleButtonProps & ButtonProps
>(function CollapsibleButton({ defaultChecked, children, ...props }, ref) {
  return (
    <Button
      ref={ref}
      variant="contained"
      component="label"
      tabIndex={-1}
      role={undefined}
      {...props}
    >
      <ScreenReaderInput type="checkbox" defaultChecked={defaultChecked} />
      {children}
    </Button>
  );
}) as OverridableComponent<CollapsibleButtonProps, typeof Button>;

export const collapsibleClasses = {
  trigger: "CollapsibleTrigger",
  content: "CollapsibleContent",
  icon: "CollapsibleIcon",
};

"use client";

import React from "react";

import { styled } from "@mui/material/styles";

import type {
  ForwardStyledProps,
  OverridableComponent,
} from "../../types/shared/component";
import { collapsibleClasses } from "./collapsible-classes";

export type CollapsibleContentProps = ForwardStyledProps<{
  component?: React.ElementType;
}>;

const StyledCollapsibleContent = styled("div", {
  name: "CollapsibleContent",
  slot: "root",
})({
  "--_i-uncollapsed": "var(--__)", // default when not within EdgeSidebarContent
  "--_i-collapsed": "var(--__,)", // value is ignored by default.
  display: "grid",
  "& > *": {
    overflow: "hidden",
  },
  "label:has(:checked) ~ &": {
    transition:
      "var(--tsn, grid-template-rows 0.4s, visibility 0.4s, opacity 0.4s 0.2s)",
    gridTemplateRows: "var(--_i-collapsed, 0fr) var(--_i-uncollapsed, 1fr)",
    [`& .SidebarMenuButton`]: {
      visibility: "var(--_i-collapsed, hidden)" as never,
    },
  },
  "label:not(:has(:checked)) ~ &": {
    gridTemplateRows: "0fr",
    visibility: "hidden",
    opacity: 0,
    transition:
      "var(--tsn, grid-template-rows 0.4s, visibility 0.4s, opacity 0.2s)",
    [`& .SidebarMenuAction`]: {
      visibility: "hidden",
    },
  },
  ".EdgeSidebarContent &": {
    "--_i-collapsed": "var(--_collapsed)",
    "--_i-uncollapsed": "var(--_uncollapsed)",
  },
});

export const CollapsibleContent = React.forwardRef<
  HTMLDivElement,
  CollapsibleContentProps & React.ComponentPropsWithoutRef<"div">
>(function CollapsibleContent({ className, component, ...props }, ref) {
  return (
    <StyledCollapsibleContent
      ref={ref}
      className={`${collapsibleClasses.content} ${className || ""}`}
      as={component}
      {...props}
    />
  );
}) as OverridableComponent<CollapsibleContentProps, "div">;

"use client";

import React from "react";

import { styled } from "@mui/material/styles";

import type { ForwardStyledProps } from "../../types/shared/component";
import { collapsibleClasses } from "./collapsible-classes";

export type CollapsibleIconProps = ForwardStyledProps<{
  rotate?: string;
}>;

const StyledCollapsibleIcon = styled("span", {
  name: "CollapsibleIcon",
  slot: "root",
})({
  "--_i-uncollapsed": "var(--__)", // default when not within EdgeSidebarContent
  "--_i-collapsed": "var(--__,)", // value is ignored by default.
  flex: "none",
  transition:
    "var(--tsn, transform cubic-bezier(0.4, 0, 0.2, 1) 0.15s, visibility 0s var(--_i-uncollapsed, 0.1s))",
  visibility: "var(--_i-collapsed, hidden)" as never,
  display: "inline-flex",
  alignItems: "center",
  justifyContent: "center",
  [`.SidebarMenuButton &`]: {
    position: "absolute",
    right: "var(--item-px, 0.5rem)",
  },
  "label:has(:checked) &": {
    transform: "rotate(var(--collapsible-rotate))",
  },
  ".EdgeSidebarContent &": {
    "--_i-collapsed": "var(--_collapsed)",
    "--_i-uncollapsed": "var(--_uncollapsed)",
  },
});

export const CollapsibleIcon = React.forwardRef<
  HTMLSpanElement,
  CollapsibleIconProps & React.ComponentPropsWithoutRef<"span">
>(function CollapsibleIcon(
  { className, rotate = "180deg", style, ...props },
  ref,
) {
  return (
    <StyledCollapsibleIcon
      ref={ref}
      className={`${collapsibleClasses.icon} ${className || ""}`}
      style={
        {
          ...style,
          "--collapsible-rotate": `-${rotate}`,
        } as React.CSSProperties
      }
      {...props}
    />
  );
});

"use client";
import React from "react";
import { styled } from "@mui/material/styles";

interface CollapsibleTriggerProps {
  defaultChecked?: boolean;
  render: React.ReactNode;
}

export const ScreenReaderInput = styled("input")({
  position: "absolute",
  width: 1,
  height: 1,
  padding: 0,
  margin: -1,
  overflow: "hidden",
  clip: "rect(0, 0, 0, 0)",
  whiteSpace: "nowrap",
  borderWidth: 0,
});

const CollapsibleTrigger = function CollapsibleTrigger({
  className,
  defaultChecked,
  render,
  ...props
}: Omit<React.ComponentPropsWithoutRef<"label">, "defaultChecked"> &
  CollapsibleTriggerProps) {
  return React.cloneElement(render as React.ReactElement, {
    // @ts-expect-error to allow passing props to non-HTML element for flexibility, e.g. SidebarMenuButton
    component: "label",
    role: undefined, // to prevent the custom role on rendered element.
    tabIndex: -1, // to prevent focus on the label element, focus should be on the input element for accessibility
    defaultChecked,
    _before: (
      <ScreenReaderInput type="checkbox" defaultChecked={defaultChecked} />
    ),
    ...props,
  });
};

export { CollapsibleTrigger };

export * from "./collapsible-classes";
export * from "./collapsible-trigger";
export * from "./collapsible-button";
export * from "./collapsible-content";
export * from "./collapsible-icon";
